1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function countByType(items: any[]): Record<string, number> {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] ?? 0) + 1;
21	  }
22	  return counts;
23	}
24	
25	function calculateBasePremium(typeCounts: Record<string, number>): number {
26	  let total = 0;
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
29	      total += BLOCK_PREMIUM;
30	    } else {
31	      total += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	  return total;
35	}
36	
37	const CURSED_SURCHARGE_RATE = 0.5;
38	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const ENCHANTMENT_THRESHOLD = 5;
40	
41	function calculateItemSurcharges(items: any[]): number {
42	  let total = 0;
43	  for (const item of items) {
44	    const base = BASE_PREMIUM[item.type] ?? 0;
45	    if (item.cursed) {
46	      total += base * CURSED_SURCHARGE_RATE;
47	    }
48	    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
49	      total += base * ENCHANTMENT_SURCHARGE_RATE;
50	    }
51	  }
52	  return total;
53	}
54	
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_THRESHOLD_YEARS = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
58	
59	function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
60	  const typeCounts = countByType(items);
61	  const basePremium = calculateBasePremium(typeCounts);
62	  const itemSurcharges = calculateItemSurcharges(items);
63	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
64	  const loyaltyDiscount = (customer.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
65	    ? basePremium * LOYALTY_DISCOUNT_RATE
66	    : 0;
67	  const followUpDiscount = quoteIndex >= 1
68	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
69	    : 0;
70	  return Math.ceil(basePremium + itemSurcharges - loyaltyDiscount + firstInsurance - followUpDiscount + PROCESSING_FEE);
71	}
72	
73	export function processScenario(scenario: any): unknown {
74	  const results = scenario.steps.map((step: any, index: number) => ({
75	    premium: calculateQuotePremium(step.items, scenario.customer, index),
76	  }));
77	
78	  return { results };
79	}
